// Tbl3dsRequestXxxxxArg Xxxxx 查询参数
type Tbl3dsRequestXxxxxArg struct {
	FieldMask *conditonwhere.FieldMask
	RRN string
}

func (tbl3dsRequestXxxxxArg *Tbl3dsRequestXxxxxArg) WithRRN(RRN string) *Tbl3dsRequestXxxxxArg{
	tbl3dsRequestXxxxxArg.RRN = RRN
	tbl3dsRequestXxxxxArg.FieldMask.Set("RRN")
	return tbl3dsRequestXxxxxArg
} 

// ConvertToMap 将参数转换为map
func (tbl3dsRequestXxxxxArg *Tbl3dsRequestXxxxxArg) ConvertToMap() map[string]interface{} {
	if tbl3dsRequestXxxxxArg == nil {
		return nil
	}
	return map[string]interface{}{
		"RRN": tbl3dsRequestXxxxxArg.RRN,
	}
}



