var Tbl3dsRequestWhereDataToYAMLCache = map[string]string{
	"Xxxxx":`conditions:
- expr: RETRIEVAL_REFERENCE_NUMBER = @RRN
operator: AND
`,
}


var Tbl3dsRequestConditionMap = map[string]*conditonwhere.MaskWhereCondition{}

// 初始注册自定义函数的condition
func init() {
	for key, whereDataYaml := range Tbl3dsRequestWhereDataToYAMLCache {
		var newData map[interface{}]interface{}
		yaml.Unmarshal([]byte(whereDataYaml), &newData)
		 Tbl3dsRequestConditionMap[key] = conditonwhere.ParseWhereCondition(newData)
	}
}
